  ('L-Asparagin', 'Molmasse', 'g/mol', '132,12 g/mol (wasserfrei); 150,13 g/mol (Monohydrat)', 'CAS 70-47-3 (wasserfrei), CAS 5794-13-8 (Monohydrat)'),
